body:
long result = ${1:call};
if (result_is_error(result)) {
    eprintf("${2:call} failed: %s\n", result_error_string(result));
    return 1;
}

long result = ${1:call};
if (result_is_error(result)) {
    int code = result_error_code(result);
    eprintf("${2:call} failed (%d): %s\n", code, error_string(code));
    return 1;
}

long fd = open("${1:/disk/tmp/example.txt}");
if (result_is_error(fd)) {
    eprintf("open failed: %s\n", result_error_string(fd));
    return 1;
}

const char* text = "${2:hello}\n";
long wrote = write((int)fd, text, strlen(text));
if (result_is_error(wrote)) {
    eprintf("write failed: %s\n", result_error_string(wrote));
    close((int)fd);
    return 1;
}

close((int)fd);

long mk = mkdir("${1:/disk/tmp}");
if (result_is_error(mk) && result_error_code(mk) != SAVANXP_EEXIST) {
    eprintf("mkdir failed: %s\n", result_error_string(mk));
    return 1;
}

long mv = rename("${2:/disk/tmp/source.txt}", "${3:/disk/tmp/dest.txt}");
if (result_is_error(mv)) {
    eprintf("rename failed: %s\n", result_error_string(mv));
    return 1;
}

long trunc = truncate("${1:/disk/tmp/example.txt}", ${2:0});
if (result_is_error(trunc)) {
    eprintf("truncate failed: %s\n", result_error_string(trunc));
    return 1;
}

long rm = unlink("${1:/disk/tmp/example.txt}");
if (result_is_error(rm)) {
    eprintf("unlink failed: %s\n", result_error_string(rm));
    return 1;
}

const char* argv[] = { "${1:hello}", "${2:arg}", 0 };
long pid = spawn("${3:/disk/bin/hello}", argv, 2);
if (result_is_error(pid)) {
    eprintf("spawn failed: %s\n", result_error_string(pid));
    return 1;
}

int status = 0;
long waited = waitpid((int)pid, &status);
if (result_is_error(waited)) {
    eprintf("waitpid failed: %s\n", result_error_string(waited));
    return 1;
}

printf("child status=%d\n", status);

unsigned long before = uptime_ms();
sleep_ms(${1:250});
unsigned long after = uptime_ms();
printf("slept for %lu ms\n", after - before);

struct savanxp_process_info info;
for (unsigned long index = 0;; ++index) {
    long result = proc_info(index, &info);
    if (result_is_error(result)) {
        if (result_error_code(result) == SAVANXP_ENOENT) {
            break;
        }
        eprintf("proc_info failed: %s\n", result_error_string(result));
        return 1;
    }

    printf("pid=%d state=%s name=%s\n", info.pid, process_state_string(info.state), info.name);
}
